import React, { useState } from "react";
import "./DropCourse.css";

function DropCourse() {
  const [studentId, setStudentId] = useState("");
  const [courseId, setCourseId] = useState("");
  const [reason, setReason] = useState("");

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log({ studentId, courseId, reason });
  };

  return (
    <>
    <form className="drop-form" onSubmit={handleSubmit}>
      <label>Student ID</label>
      <input type="text" value={studentId} onChange={(e) => setStudentId(e.target.value)} required />
      <label>Course ID</label>
      <input type="text" value={courseId} onChange={(e) => setCourseId(e.target.value)} required />
      <label>Reason</label>
      <textarea value={reason} onChange={(e) => setReason(e.target.value)} required />
      <button type="submit">Drop Course</button>
    </form>
    </>
  );
}

export default DropCourse;
